package main

import "fmt"

type Backend struct {
    URL               string
    Alive             bool
    ActiveConnections int
}

func (b *Backend) IncrementConnections() {
    b.ActiveConnections++
}

func (b Backend) ConnectionCount() int {
    return b.ActiveConnections
}

func main() {
    b := Backend{URL: "http://localhost:8080", Alive: true}
    b.IncrementConnections()
    b.IncrementConnections()
    b.IncrementConnections()
    fmt.Println(b.ConnectionCount()) // 3
}
```

