Given the `Backend` struct below, explain why calling `b.SetAlive(false)` does NOT change `b.Alive` to `false`, then fix it:

```go
type Backend struct {
    URL   string
    Alive bool
}

func (b Backend) SetAlive(alive bool) {
    b.Alive = alive
}

func main() {
    b := Backend{URL: "http://localhost:9090", Alive: true}
    b.SetAlive(false)
    fmt.Println(b.Alive) // prints: true  — why?
}
